'use client';
import { useCart } from '@/context/CartContext';
import { useAuth } from '@/context/AuthContext';
import { supabase } from '@/lib/supabase';
import { useRouter } from 'next/navigation';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { Trash2, ShoppingBag, Plus, Minus, ArrowRight, Loader2, Package, CheckCircle2, MapPin, Phone, User } from 'lucide-react';
import Link from 'next/link';
import { useState } from 'react';

export default function CartPage() {
  const { cart, removeFromCart, updateQuantity, clearCart, getCartTotal } = useCart();
  const { session } = useAuth();
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [createdOrders, setCreatedOrders] = useState([]);
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');

  const total = getCartTotal();
  const totalItems = cart.reduce((acc, item) => acc + item.quantity, 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setError('');

    if (!name.trim() || !phone.trim()) {
      setError('Veuillez entrer votre nom et numéro de téléphone pour la livraison.');
      return;
    }

    setLoading(true);
    try {
      // Obtenir la position GPS du client si possible
      let lat = null, lng = null;
      if (navigator.geolocation) {
        try {
          const pos = await new Promise((resolve, reject) => {
            navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 8000, enableHighAccuracy: true });
          });
          lat = pos.coords.latitude;
          lng = pos.coords.longitude;
        } catch (e) {
          console.warn("GPS non disponible ou refusé.", e);
        }
      }

      const storeIds = [...new Set(cart.map(item => item.store_id))];
      const newOrders = [];

      for (const storeId of storeIds) {
        const storeItems = cart.filter(item => item.store_id === storeId);
        const storeTotal = storeItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const fullName = address ? `${name} (Adresse: ${address})` : name;

        const { data, error: orderError } = await supabase.from('orders').insert([{
          store_id: storeId,
          customer_name: fullName,
          customer_phone: phone,
          total_amount: storeTotal,
          order_items: storeItems,
          delivery_lat: lat,
          delivery_lng: lng
        }]).select('id, created_at, store_id').single();

        if (orderError) throw orderError;
        if (data) newOrders.push({ id: data.id, created_at: data.created_at, store_id: data.store_id });
      }

      // Save to localStorage (expire in 30 days handled when reading)
      const existing = JSON.parse(localStorage.getItem('vestyle_orders') || '[]');
      localStorage.setItem('vestyle_orders', JSON.stringify([...existing, ...newOrders]));

      clearCart();
      setCreatedOrders(newOrders);
    } catch (e) {
      console.error(e);
      setError('Erreur lors de la validation : ' + (e.message || 'Erreur inconnue'));
    } finally {
      setLoading(false);
    }
  };

  if (createdOrders.length > 0) {
    return (
      <main className="bg-wa-bg min-h-screen flex flex-col font-sans">
        <Navbar />
        <div className="flex-1 flex flex-col items-center justify-center px-4 py-20 text-center">
          <div className="w-20 h-20 bg-wa-green rounded-full flex items-center justify-center mb-6 shadow-md">
            <CheckCircle2 size={40} className="text-white" />
          </div>
          <h1 className="text-3xl font-bold text-wa-teal-dark mb-4">
            Commande validée !
          </h1>
          <p className="text-neutral-600 max-w-md mx-auto mb-8">
            Votre commande a été transmise au(x) vendeur(s). Ils vous contacteront rapidement pour la livraison.
          </p>

          <Link
            href="/"
            className="flex items-center justify-center gap-2 px-8 py-3.5 bg-wa-teal text-white rounded-full font-bold shadow-sm hover:bg-wa-teal-dark transition-all"
          >
            Retour à l'accueil
          </Link>
        </div>
      </main>
    );
  }

  return (
    <main className="bg-wa-bg min-h-screen flex flex-col font-sans">
      <Navbar />

      <div className="flex-1 max-w-5xl mx-auto w-full px-4 pt-24 sm:pt-32 pb-32">

        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 bg-wa-teal rounded-full flex items-center justify-center shadow-sm">
              <ShoppingBag size={22} className="text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-wa-teal-dark leading-none">Mon Panier</h1>
              {cart.length > 0 && (
                <p className="text-sm text-neutral-500 mt-1">{totalItems} article{totalItems > 1 ? 's' : ''}</p>
              )}
            </div>
          </div>
        </div>

        {cart.length === 0 ? (
          <div className="bg-white rounded-3xl p-12 text-center shadow-sm">
            <div className="w-20 h-20 bg-neutral-50 rounded-full flex items-center justify-center mb-5 mx-auto">
              <ShoppingBag size={34} className="text-neutral-300" />
            </div>
            <h2 className="text-xl font-bold text-neutral-800 mb-2">Votre panier est vide</h2>
            <p className="text-neutral-500 text-sm mb-8">Ajoutez des produits depuis les boutiques locales.</p>
            <Link
              href="/"
              className="inline-flex items-center gap-2 bg-wa-green text-white px-8 py-3.5 rounded-full font-bold hover:bg-wa-teal transition-colors shadow-sm"
            >
              Découvrir les boutiques
            </Link>
          </div>
        ) : (
          <div className="flex flex-col lg:flex-row gap-6">

            {/* Cart Items */}
            <div className="flex-1 flex flex-col gap-3">

                {cart.map((item) => (
                  <div>
                    {/* Image */}
                    <div className="w-20 h-20 sm:w-24 sm:h-24 rounded-xl overflow-hidden flex-shrink-0 bg-neutral-100">
                      {item.image_url ? (
                        <img src={item.image_url} alt={item.name} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-neutral-300">
                          <Package size={28} />
                        </div>
                      )}
                    </div>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <h3 className="font-bold text-wa-teal-dark text-sm leading-snug line-clamp-1">{item.name}</h3>
                      <p className="text-wa-teal font-black text-sm mt-1">{(item.price * item.quantity).toLocaleString()} FCFA</p>
                      <p className="text-neutral-400 text-xs mt-0.5">{item.price.toLocaleString()} FCFA / unité</p>
                    </div>

                    {/* Qty & Delete */}
                    <div className="flex flex-col items-end gap-3 flex-shrink-0">
                      <button
                        onClick={() => removeFromCart(item.id)}
                        className="w-7 h-7 flex items-center justify-center rounded-lg text-neutral-300 hover:text-red-500 hover:bg-red-50 transition-colors"
                      >
                        <Trash2 size={14} />
                      </button>
                      <div className="flex items-center gap-2 bg-neutral-50 border border-neutral-200 rounded-xl p-1">
                        <button
                          onClick={() => updateQuantity(item.id, item.quantity - 1)}
                          className="w-6 h-6 flex items-center justify-center rounded-lg text-neutral-500 hover:bg-white hover:text-wa-teal transition-colors"
                        >
                          <Minus size={12} />
                        </button>
                        <span className="text-sm font-bold w-5 text-center text-neutral-900">{item.quantity}</span>
                        <button
                          onClick={() => updateQuantity(item.id, item.quantity + 1)}
                          className="w-6 h-6 flex items-center justify-center rounded-lg text-neutral-500 hover:bg-white hover:text-wa-teal transition-colors"
                        >
                          <Plus size={12} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))}


              {/* Clear Cart */}
              <div className="flex justify-end pt-1">
                <button
                  onClick={clearCart}
                  className="text-xs text-neutral-400 hover:text-red-500 underline underline-offset-2 transition-colors"
                >
                  Vider le panier
                </button>
              </div>
            </div>

            {/* Order Summary */}
            <div className="w-full lg:w-[380px] flex-shrink-0">
              <div className="bg-white rounded-3xl border border-neutral-100 shadow-sm sticky top-28 overflow-hidden">

                {/* Summary Header */}
                <div className="px-6 pt-6 pb-4 border-b border-neutral-100">
                  <h3 className="font-black text-neutral-900 text-base">Résumé</h3>
                  <div className="flex justify-between text-sm text-neutral-500 mt-3">
                    <span>Sous-total ({totalItems} art.)</span>
                    <span className="font-semibold text-neutral-800">{total.toLocaleString()} FCFA</span>
                  </div>
                  <div className="flex justify-between text-sm text-neutral-500 mt-1.5">
                    <span>Livraison</span>
                    <span className="font-semibold text-emerald-500">Offerte</span>
                  </div>
                  <div className="flex justify-between text-base font-bold text-wa-teal-dark mt-4 pt-4 border-t border-neutral-100">
                    <span>Total</span>
                    <span className="text-wa-teal">{total.toLocaleString()} FCFA</span>
                  </div>
                </div>

                {/* Delivery Form */}
                <div className="px-6 py-5 flex flex-col gap-4">
                  <p className="text-xs font-bold text-neutral-400 uppercase tracking-wider">Informations de livraison</p>

                  <div className="relative">
                    <User size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-neutral-400" />
                    <input
                      type="text"
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      placeholder="Nom complet *"
                      className="w-full pl-9 pr-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl text-sm text-neutral-900 placeholder-neutral-400 focus:outline-none focus:border-wa-teal transition-colors"
                    />
                  </div>

                  <div className="relative">
                    <Phone size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-neutral-400" />
                    <input
                      type="tel"
                      value={phone}
                      onChange={(e) => setPhone(e.target.value)}
                      placeholder="Téléphone *"
                      className="w-full pl-9 pr-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl text-sm text-neutral-900 placeholder-neutral-400 focus:outline-none focus:border-wa-teal transition-colors"
                    />
                  </div>

                  <div className="relative">
                    <MapPin size={15} className="absolute left-3.5 top-3.5 text-neutral-400" />
                    <textarea
                      value={address}
                      onChange={(e) => setAddress(e.target.value)}
                      placeholder="Adresse de livraison"
                      rows={2}
                      className="w-full pl-9 pr-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl text-sm text-neutral-900 placeholder-neutral-400 focus:outline-none focus:border-wa-teal transition-colors resize-none"
                    />
                  </div>

                  {error && (
                    <div className="text-xs text-red-500 bg-red-50 border border-red-100 rounded-xl p-3">
                      {error}
                    </div>
                  )}
                </div>

                {/* CTA */}
                <div className="px-6 pb-6">
                  <button
                    onClick={handleCheckout}
                    disabled={loading}
                    className="w-full h-14 bg-wa-green hover:bg-wa-teal text-white rounded-full font-bold text-sm transition-all flex items-center justify-center gap-2 shadow-sm disabled:opacity-60 disabled:cursor-not-allowed"
                  >
                    {loading ? (
                      <Loader2 size={20} className="animate-spin" />
                    ) : (
                      <>Valider la commande <ArrowRight size={18} /></>
                    )}
                  </button>
                </div>
              </div>
            </div>

          </div>
        )}
      </div>

      <Footer />
    </main>
  );
}

'use client';
import { useEffect, useRef, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/context/AuthContext';
import { deleteCloudinaryByUrl, uploadImage } from '@/lib/cloudinary';
import { useRouter } from 'next/navigation';
import { ImagePlus, Package, ArrowLeft, Loader2, Save } from 'lucide-react';
import Link from 'next/link';

export default function AddProductPage() {
  const { session } = useAuth();
  const router = useRouter();

  const [storeId, setStoreId] = useState(null);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [uploadingImage, setUploadingImage] = useState(false);
  const tempUploadedUrlsRef = useRef(new Set());
  const saveSucceededRef = useRef(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    category_id: '',
    price: '',
    stock_quantity: '1',
    image_url: ''
  });

  useEffect(() => {
    if (!session?.id) return;
    async function fetchStore() {
      const { data } = await supabase.from('stores').select('id').eq('owner_id', session.id).single();
      if (data) setStoreId(data.id);
    }
    fetchStore();
  }, [session]);

  useEffect(() => {
    if (!storeId) return;

    async function fetchCategories() {
      const { data } = await supabase
        .from('categories')
        .select('id, name')
        .eq('store_id', storeId)
        .order('name', { ascending: true });

      if (data) {
        setCategories(data);
      }
    }

    fetchCategories();
  }, [storeId]);

  useEffect(() => {
    return () => {
      if (saveSucceededRef.current) return;

      const pending = Array.from(tempUploadedUrlsRef.current);
      pending.forEach((url) => {
        deleteCloudinaryByUrl(url);
      });
    };
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleImageFile = async (file) => {
    if (!file) return;

    try {
      setUploadingImage(true);
      const previousUrl = formData.image_url;
      const { secureUrl } = await uploadImage(file, { folder: 'vestyle/products' });
      if (!secureUrl) {
        throw new Error("Upload invalide");
      }

      if (previousUrl && previousUrl !== secureUrl && tempUploadedUrlsRef.current.has(previousUrl)) {
        await deleteCloudinaryByUrl(previousUrl);
        tempUploadedUrlsRef.current.delete(previousUrl);
      }

      setFormData((prev) => ({ ...prev, image_url: secureUrl }));
      tempUploadedUrlsRef.current.add(secureUrl);
    } catch (err) {
      alert("Erreur upload image: " + (err?.message || "Impossible de televerser l'image"));
    } finally {
      setUploadingImage(false);
    }
  };

  const handleRemoveImage = async () => {
    const currentUrl = formData.image_url;
    if (!currentUrl) return;

    if (tempUploadedUrlsRef.current.has(currentUrl)) {
      await deleteCloudinaryByUrl(currentUrl);
      tempUploadedUrlsRef.current.delete(currentUrl);
    }

    setFormData((prev) => ({ ...prev, image_url: '' }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!storeId) {
      alert("Aucune boutique liée !");
      return;
    }

    setLoading(true);
    const { error } = await supabase.from('products').insert([{
      store_id: storeId,
      category_id: formData.category_id || null,
      name: formData.name,
      description: formData.description,
      price: parseFloat(formData.price),
      stock_quantity: parseInt(formData.stock_quantity),
      image_url: formData.image_url || null
    }]);

    setLoading(false);
    if (error) {
      alert("Erreur lors de la création : " + error.message);
    } else {
      const currentImage = formData.image_url;
      const staleTemps = Array.from(tempUploadedUrlsRef.current).filter((url) => url && url !== currentImage);
      if (staleTemps.length > 0) {
        await Promise.allSettled(staleTemps.map((url) => deleteCloudinaryByUrl(url)));
      }

      saveSucceededRef.current = true;
      tempUploadedUrlsRef.current.clear();
      router.push('/dashboard');
    }
  };

  if (session === undefined) return <div className="min-h-screen bg-wa-bg flex justify-center items-center"><Loader2 className="animate-spin text-wa-teal" size={48} /></div>;

  return (
    <div className="space-y-8">
      <Link href="/dashboard" className="flex items-center gap-2 text-sm text-neutral-500 hover:text-neutral-900 mb-6 font-medium transition-colors w-max">
        <ArrowLeft size={16} /> Revenir au catalogue
      </Link>

      <header className="mb-10">
        <h1 className="text-3xl font-bold text-wa-teal-dark flex items-center gap-3"><Package size={28} className="text-wa-teal"/> Ajouter un produit</h1>
        <p className="text-neutral-500 mt-2 text-sm">Créez une nouvelle fiche produit qui sera immédiatement visible sur votre boutique Vestyle.</p>
      </header>

      <form onSubmit={handleSubmit} className="max-w-2xl bg-white border border-neutral-200 rounded-3xl p-8 shadow-sm">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="md:col-span-2">
            <label className="block text-sm font-bold text-neutral-900 mb-2">Nom du produit *</label>
            <input required type="text" name="name" value={formData.name} onChange={handleChange} placeholder="Ex: T-Shirt Vintage Oversize" className="w-full bg-neutral-50 border border-neutral-200 text-neutral-900 rounded-xl px-4 py-3 focus:outline-none focus:border-wa-teal transition-colors" />
          </div>

          <div className="md:col-span-2">
            <label className="block text-sm font-bold text-neutral-900 mb-2">Description</label>
            <textarea name="description" value={formData.description} onChange={handleChange} rows="4" placeholder="Décrivez votre produit en détail (matière, conseils d&apos;entretien...)" className="w-full bg-neutral-50 border border-neutral-200 text-neutral-900 rounded-xl px-4 py-3 focus:outline-none focus:border-wa-teal transition-colors"></textarea>
          </div>

          <div>
            <label className="block text-sm font-bold text-neutral-900 mb-2">Prix (XAF) *</label>
            <input required type="number" min="0" name="price" value={formData.price} onChange={handleChange} placeholder="Ex: 15000" className="w-full bg-neutral-50 border border-neutral-200 text-neutral-900 rounded-xl px-4 py-3 focus:outline-none focus:border-wa-teal transition-colors" />
          </div>

          <div>
            <label className="block text-sm font-bold text-neutral-900 mb-2">Stock disponible *</label>
            <input required type="number" min="1" name="stock_quantity" value={formData.stock_quantity} onChange={handleChange} placeholder="Ex: 10" className="w-full bg-neutral-50 border border-neutral-200 text-neutral-900 rounded-xl px-4 py-3 focus:outline-none focus:border-wa-teal transition-colors" />
          </div>

          <div className="md:col-span-2">
            <label className="block text-sm font-bold text-neutral-900 mb-2">Catégorie</label>
            <select
              name="category_id"
              value={formData.category_id}
              onChange={handleChange}
              className="w-full bg-neutral-50 border border-neutral-200 text-neutral-900 rounded-xl px-4 py-3 focus:outline-none focus:border-wa-teal"
            >
              <option value="">Aucune catégorie</option>
              {categories.map((category) => (
                <option key={category.id} value={category.id}>
                  {category.name}
                </option>
              ))}
            </select>
            {categories.length === 0 && (
              <p className="text-xs text-neutral-500 mt-2">Aucune catégorie trouvée, le produit sera créé sans catégorie.</p>
            )}
          </div>

          <div className="md:col-span-2">
            <label className="block text-sm font-bold text-neutral-900 mb-2">Url de l&apos;image (Optionnel)</label>
            <div className="flex gap-3 items-center">
              <div className="flex-1 relative">
                <ImagePlus size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
                <input type="url" name="image_url" value={formData.image_url} onChange={handleChange} placeholder="https://lien... (Ou connectez Supabase Storage plus tard)" className="w-full bg-neutral-50 border border-neutral-200 text-neutral-900 rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:border-wa-teal transition-colors" />
              </div>
            </div>
            <div className="mt-3">
              <div className="flex flex-wrap items-center gap-2">
                <label className="inline-flex items-center px-4 py-2 rounded-xl border border-neutral-200 bg-neutral-50 text-sm font-medium text-neutral-700 cursor-pointer hover:bg-neutral-100 transition-colors">
                  Choisir une image locale
                  <input
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={(e) => handleImageFile(e.target.files?.[0])}
                  />
                </label>
                {formData.image_url && (
                  <button
                    type="button"
                    onClick={handleRemoveImage}
                    className="px-4 py-2 rounded-xl border border-red-200 bg-red-50 text-sm font-medium text-red-700 hover:bg-red-100 transition-colors"
                  >
                    Supprimer l&apos;image
                  </button>
                )}
              </div>
              {uploadingImage && <p className="text-xs text-neutral-500 mt-2">Upload de l&apos;image en cours...</p>}
            </div>
          </div>
        </div>

        <div className="mt-8 pt-6 border-t border-neutral-100 flex items-center justify-end gap-4">
          <Link href="/dashboard" className="px-6 py-3 rounded-xl font-bold text-neutral-600 hover:bg-neutral-100 transition-colors">Annuler</Link>
          <button disabled={loading} type="submit" className="bg-wa-green disabled:bg-neutral-300 disabled:text-neutral-500 hover:bg-wa-teal text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 transition-colors shadow-sm">
            {loading ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />} Enregistrer le produit
          </button>
        </div>
      </form>
    </div>
  );
}

