}

import { useState, useEffect } from 'react';
import { X, Upload, CheckCircle2, AlertCircle, Loader2 } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { uploadImage } from '@/lib/cloudinary';
import { productsIndex } from '@/lib/meilisearch';


export default function AddProductModal({ onClose, categories = [], storeId, onSuccess, productToEdit = null }) {
  const [name, setName] = useState(productToEdit?.name || '');
  const [description, setDescription] = useState(productToEdit?.description || '');
  const [price, setPrice] = useState(productToEdit?.price || '');
  const [stock, setStock] = useState(productToEdit?.stock_quantity || '');
  const [categoryId, setCategoryId] = useState(productToEdit?.category_id || '');
  const [imageUrl, setImageUrl] = useState(productToEdit?.image_url || '');
  const [uploadingImage, setUploadingImage] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const isEdit = !!productToEdit;

  const handleImageFile = async (file) => {
    if (!file) return;

    try {
      setUploadingImage(true);
      const { secureUrl } = await uploadImage(file, { folder: 'vestyle/products' });
      if (!secureUrl) throw new Error('Upload image invalide');
      setImageUrl(secureUrl);
    } catch (err) {
      setError("Erreur upload image. Verifiez votre connexion.");
    } finally {
      setUploadingImage(false);
    }
  };

  const handleSave = async () => {
    if (!name || !price || !categoryId) {
      setError('Champs obligatoires : Nom, Prix, Catégorie.');
      return;
    }

    setLoading(true);
    setError('');

    const productData = {
      store_id: storeId,
      category_id: categoryId,
      name,
      description,
      price: parseFloat(price),
      stock_quantity: parseInt(stock) || 0,
      image_url: imageUrl || null,
      is_active: true
    };

    try {
      let savedProduct;
      if (isEdit) {
        const { data, error: updateError } = await supabase
          .from('products')
          .update(productData)
          .eq('id', productToEdit.id)
          .select()
          .single();
        if (updateError) throw updateError;
        savedProduct = data;
      } else {
        const { data, error: insertError } = await supabase
          .from('products')
          .insert([productData])
          .select()
          .single();
        if (insertError) throw insertError;
        savedProduct = data;
      }

      // Indexation en temps réel dans Meilisearch
      try {
        await productsIndex.addDocuments([savedProduct]);
      } catch (meiliErr) {
        console.error('Meilisearch Sync Error:', meiliErr);
      }

      if(onSuccess) onSuccess(savedProduct);
    } catch (err) {
      setError(isEdit ? 'Erreur lors de la modification.' : 'Erreur lors de la création.');
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 sm:p-6 overflow-y-auto">
      <div
        onClick={onClose}
        className="fixed inset-0 bg-black/60 backdrop-blur-sm"
      />

      <div
        className="relative w-full max-w-2xl bg-white rounded-[32px] shadow-2xl overflow-hidden"
      >
        <div className="px-4 sm:px-8 py-4 sm:py-6 border-b border-gray-100 flex items-center justify-between bg-white sticky top-0 z-10">
          <div>
            <h2 className="text-xl sm:text-2xl font-black text-gray-900 tracking-tight">
              {isEdit ? 'Modifier le Produit' : 'Nouveau Produit'}
            </h2>
            <p className="text-[10px] sm:text-sm text-gray-500 font-medium uppercase tracking-wider">
              {isEdit ? 'Mettez à jour les informations de votre article.' : 'Ajoutez une pépite à votre catalogue.'}
            </p>
          </div>
          <button onClick={onClose} className="p-2 sm:p-2.5 bg-gray-50 text-gray-400 hover:text-gray-900 hover:bg-gray-100 rounded-xl sm:rounded-2xl transition-all">
             <X size={18} className="sm:w-5 sm:h-5" />
          </button>
        </div>

        <div className="p-4 sm:p-8 space-y-4 sm:space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar text-left">
           {error && (
             <div className="flex items-center gap-3 p-4 bg-rose-50 text-rose-600 rounded-2xl text-sm font-bold border border-rose-100">
               <AlertCircle size={18} />
               {error}
             </div>
           )}

           <div className="space-y-2">
              <label className="text-[10px] sm:text-sm font-black text-gray-700 uppercase tracking-wider ml-1">Nom du produit *</label>
              <input type="text" placeholder="Ex: Robe d'été en lin" className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-xl sm:rounded-2xl px-4 sm:px-5 py-3 sm:py-4 text-sm sm:text-base text-gray-900 font-medium outline-none transition-all placeholder:text-gray-400" value={name} onChange={e => setName(e.target.value)}/>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] sm:text-sm font-black text-gray-700 uppercase tracking-wider ml-1">Prix (FCFA) *</label>
                <input type="number" placeholder="0" className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-xl sm:rounded-2xl px-4 sm:px-5 py-3 sm:py-4 text-sm sm:text-base text-gray-900 font-medium outline-none transition-all" value={price} onChange={e => setPrice(e.target.value)}/>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] sm:text-sm font-black text-gray-700 uppercase tracking-wider ml-1">Quantité en Stock</label>
                <input type="number" placeholder="0" className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-xl sm:rounded-2xl px-4 sm:px-5 py-3 sm:py-4 text-sm sm:text-base text-gray-900 font-medium outline-none transition-all" value={stock} onChange={e => setStock(e.target.value)}/>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] sm:text-sm font-black text-gray-700 uppercase tracking-wider ml-1">Description</label>
              <textarea 
                placeholder="Matière, coupe, conseils d'entretien..." 
                className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-xl sm:rounded-2xl px-4 sm:px-5 py-3 sm:py-4 text-sm sm:text-base text-gray-900 font-medium outline-none transition-all min-h-[100px] sm:min-h-[120px] resize-none"
                value={description}
                onChange={e => setDescription(e.target.value)}
              ></textarea>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] sm:text-sm font-black text-gray-700 uppercase tracking-wider ml-1">Visuel du produit</label>
              <div className="grid grid-cols-1 sm:grid-cols-[1fr,auto] gap-3">
                <input
                  type="url"
                  placeholder="Lien de l'image (URL)..."
                  className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-xl sm:rounded-2xl px-4 sm:px-5 py-3 sm:py-4 text-sm sm:text-base text-gray-900 font-medium outline-none transition-all"
                  value={imageUrl}
                  onChange={(e) => setImageUrl(e.target.value)}
                />
                <label className="flex items-center justify-center gap-2 px-6 py-3 sm:py-4 bg-gray-100 text-gray-600 font-bold rounded-xl sm:rounded-2xl cursor-pointer hover:bg-gray-200 transition-all active:scale-95 text-sm sm:text-base">
                  <Upload size={18} className="sm:w-5 sm:h-5" />
                  <span>Upload</span>
                  <input
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={(e) => handleImageFile(e.target.files?.[0])}
                  />
                </label>
              </div>
             {uploadingImage && (
               <div className="flex items-center gap-2 text-wa-teal text-xs font-bold bg-wa-chat p-2 rounded-lg">
                 <Loader2 size={14} className="animate-spin" />
                 Téléversement en cours...
               </div>
             )}
             {imageUrl && (
                <div className="relative w-24 h-24 sm:w-32 sm:h-32 rounded-3xl overflow-hidden border-4 border-white shadow-xl">
                  <img src={imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  <button onClick={() => setImageUrl('')} className="absolute top-1 right-1 p-1 bg-white/80 rounded-full text-rose-600">
                    <X size={14} />
                  </button>
                </div>
             )}
           </div>

            <div className="space-y-2">
              <label className="text-[10px] sm:text-sm font-black text-gray-700 uppercase tracking-wider ml-1">Catégorie *</label>
              <select className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-xl sm:rounded-2xl px-4 sm:px-5 py-3 sm:py-4 text-sm sm:text-base text-gray-900 font-medium outline-none transition-all appearance-none cursor-pointer" value={categoryId} onChange={e => setCategoryId(e.target.value)}>
                 <option value="">Sélectionnez une catégorie</option>
                 {categories.map((c) => (
                   <option key={c.id} value={c.id}>{c.name}</option>
                 ))}
              </select>
            </div>
        </div>

        <div className="px-4 sm:px-8 py-4 sm:py-6 bg-gray-50 border-t border-gray-100 flex flex-col sm:flex-row items-center justify-end gap-2 sm:gap-3">
           <button className="w-full sm:w-auto px-6 py-3 sm:py-4 text-sm sm:text-base text-gray-500 font-bold hover:text-gray-900 transition-colors" onClick={onClose} disabled={loading}>Annuler</button>
           <button 
            className="w-full sm:w-auto flex items-center justify-center gap-2 sm:gap-3 px-8 py-3.5 sm:py-4 bg-wa-teal text-white font-black rounded-xl sm:rounded-2xl hover:bg-wa-teal-dark hover:shadow-xl hover:shadow-wa-teal/20 transition-all active:scale-95 disabled:bg-gray-400 disabled:shadow-none text-sm sm:text-base" 
            onClick={handleSave} 
            disabled={loading || uploadingImage}
           >
             {loading ? <Loader2 size={18} className="animate-spin" /> : <CheckCircle2 size={18} />}
             <span>{loading ? (isEdit ? 'Mise à jour...' : 'Création...') : (isEdit ? 'Enregistrer les modifications' : 'Valider le produit')}</span>
           </button>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useState, useEffect, useCallback } from 'react';
import { 
  Plus, Search, HelpCircle, Trash2, Package, Layers, 
  TrendingUp, AlertCircle, Loader2, Edit3, MoreVertical
} from 'lucide-react';
import { useAuth } from '@/context/AuthContext';
import { supabase } from '@/lib/supabase';
import { productsIndex } from '@/lib/meilisearch';
import AddProductModal from './AddProductModal';
import Image from 'next/image';

export default function ProductsPage() {
  const { store } = useAuth();
  const [products, setProducts] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [productToEdit, setProductToEdit] = useState(null);
  const [categories, setCategories] = useState([]);
  const [catInput, setCatInput] = useState('');
  const [search, setSearch] = useState('');
  const [meiliResults, setMeiliResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const [categoryLoading, setCategoryLoading] = useState(false);
  const [isSearching, setIsSearching] = useState(false);

  const fetchCategories = useCallback(async () => {
    if (!store) return;
    const { data, error } = await supabase
      .from('categories')
      .select('*')
      .eq('store_id', store.id);
    if (!error && data) setCategories(data);
  }, [store]);

  const fetchProducts = useCallback(async () => {
    if (!store) return;
    setLoading(true);
    const { data, error } = await supabase
      .from('products')
      .select('*, categories(name)')
      .eq('store_id', store.id)
      .order('created_at', { ascending: false });
    if (!error && data) setProducts(data);
    setLoading(false);
  }, [store]);

  useEffect(() => {
    if (!store) return;
    fetchCategories();
    fetchProducts();
  }, [fetchCategories, fetchProducts, store]);

  // Recherche Meilisearch avec Debounce
  useEffect(() => {
    if (!store) return;

    if (search.trim() === '') {
      setMeiliResults(null);
      setIsSearching(false);
      return;
    }

    const performSearch = async () => {
      setIsSearching(true);
      try {
        const response = await productsIndex.search(search, {
          filter: `store_id = ${store.id}`,
          limit: 50
        });
        setMeiliResults(response.hits);
      } catch (err) {
        console.error('Meilisearch search error:', err);
      } finally {
        setIsSearching(false);
      }
    };

    const timer = setTimeout(performSearch, 300);
    return () => clearTimeout(timer);
  }, [search, store]);

  const addCategory = async () => {
    if (!catInput.trim() || !store) return;
    setCategoryLoading(true);

    const strName = catInput.trim();
    const slug = strName.toLowerCase().replace(/[^a-z0-9-]/g, '-');

    const { data, error } = await supabase
      .from('categories')
      .insert([{ store_id: store.id, name: strName, slug }])
      .select()
      .single();

    if (!error && data) {
      setCategories([...categories, data]);
      setCatInput('');
    }
    setCategoryLoading(false);
  };

  const deleteProduct = async (id) => {
    if (!confirm('Voulez-vous vraiment supprimer ce produit ?')) return;
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (!error) {
      setProducts(products.filter(p => p.id !== id));
      try {
        await productsIndex.deleteDocument(id);
      } catch (err) {
        console.error('Meilisearch delete error:', err);
      }
    }
  };

  const openAddModal = () => {
    setProductToEdit(null);
    setShowAddModal(true);
  };

  const openEditModal = (product) => {
    setProductToEdit(product);
    setShowAddModal(true);
  };

  const displayProducts = meiliResults || products.filter(p => 
    p.name.toLowerCase().includes(search.toLowerCase()) ||
    (p.categories?.name || '').toLowerCase().includes(search.toLowerCase())
  );

  const stats = {
    total: products.length,
    outOfStock: products.filter(p => p.stock_quantity === 0).length,
    categories: categories.length
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-6 sm:p-8 rounded-[32px] border border-gray-100 shadow-sm text-left">
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">Catalogue Produits</h1>
          <p className="text-gray-500 font-medium mt-1">Gérez et sublimez vos articles en quelques clics.</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-5 py-3 bg-gray-50 text-gray-600 font-bold rounded-2xl hover:bg-gray-100 transition-all text-sm">
            <HelpCircle size={18} className="text-wa-teal" />
            <span className="hidden sm:inline">Aide</span>
          </button>
          <button 
            onClick={openAddModal}
            className="flex items-center gap-2 px-6 py-3 bg-wa-teal text-white font-black rounded-2xl hover:bg-wa-teal-dark hover:shadow-xl hover:shadow-wa-teal/20 transition-all active:scale-95 text-sm"
          >
            <Plus size={20} />
            <span>Nouveau Produit</span>
          </button>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        {[
          { label: 'Total Produits', value: stats.total, icon: Package, color: 'bg-wa-teal' },
          { label: 'Rupture de Stock', value: stats.outOfStock, icon: AlertCircle, color: 'bg-rose-500' },
          { label: 'Catégories', value: stats.categories, icon: Layers, color: 'bg-amber-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4 text-left">
            <div className={`${stat.color} p-3 rounded-2xl text-white shadow-lg shadow-${stat.color.split('-')[1]}-200`}>
              <stat.icon size={24} />
            </div>
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">{stat.label}</p>
              <p className="text-2xl font-black text-gray-900">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Category Management */}
        <div className="lg:col-span-1 space-y-4 text-left">
          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm space-y-6">
            <div>
              <h3 className="text-lg font-black text-gray-900">Catégories</h3>
              <p className="text-xs text-gray-500 font-medium uppercase tracking-wider mt-1">Organisez votre boutique</p>
            </div>

            <div className="space-y-3">
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="Nom de la catégorie..." 
                  className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-2xl px-4 py-3 text-sm font-medium outline-none transition-all pr-12"
                  value={catInput}
                  onChange={(e) => setCatInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addCategory()}
                />
                <button 
                  onClick={addCategory}
                  disabled={categoryLoading}
                  className="absolute right-2 top-2 p-1.5 bg-wa-teal text-white rounded-xl hover:bg-wa-teal-dark transition-all disabled:opacity-50"
                >
                  {categoryLoading ? <Loader2 size={18} className="animate-spin" /> : <Plus size={18} />}
                </button>
              </div>

              <div className="flex flex-wrap gap-2 pt-2">
                {categories.length === 0 ? (
                  <p className="text-xs text-gray-400 italic">Aucune catégorie...</p>
                ) : (
                  categories.map((c) => (
                    <span key={c.id} className="px-3 py-1.5 bg-wa-chat text-wa-teal-dark text-[10px] font-black uppercase tracking-tight rounded-lg border border-wa-teal/10">
                      {c.name}
                    </span>
                  ))
                )}
              </div>
            </div>
          </div>

          <div className="bg-gradient-to-br from-wa-teal to-wa-teal-dark p-6 rounded-3xl text-white shadow-xl shadow-wa-teal/20 relative overflow-hidden group">
            <TrendingUp size={80} className="absolute -right-4 -bottom-4 opacity-10 group-hover:scale-110 transition-transform" />
            <h4 className="text-sm font-bold opacity-80 uppercase tracking-widest mb-1">Astuce Pro</h4>
            <p className="text-xs font-medium leading-relaxed">Utilisez des noms de catégories simples pour aider vos clients à trouver leurs produits plus rapidement.</p>
          </div>
        </div>

        {/* Products Grid/List */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden text-left">
            <div className="p-4 border-b border-gray-50 bg-gray-50/50 flex items-center gap-3">
              <Search size={18} className="text-gray-400" />
              <input 
                type="text" 
                placeholder="Chercher par nom ou catégorie..." 
                className="bg-transparent border-none outline-none text-sm font-medium w-full placeholder:text-gray-400"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>

            <div className="divide-y divide-gray-50 max-h-[600px] overflow-y-auto custom-scrollbar">
              {loading || isSearching ? (
                <div className="p-12 flex flex-col items-center justify-center text-gray-400 gap-3">
                  <Loader2 className="animate-spin" size={32} />
                  <p className="text-sm font-bold uppercase tracking-widest">{isSearching ? 'Recherche...' : 'Chargement du catalogue...'}</p>
                </div>
              ) : displayProducts.length === 0 ? (
                <div className="p-16 flex flex-col items-center justify-center text-center">
                  <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center text-gray-200 mb-4">
                    <Package size={40} />
                  </div>
                  <h4 className="text-gray-900 font-black">Aucun produit</h4>
                  <p className="text-sm text-gray-500 mt-1 max-w-[200px]">Commencez par ajouter votre premier article.</p>
                </div>
              ) : (
                displayProducts.map(p => (
                  <div key={p.id} className="p-4 hover:bg-gray-50 transition-colors group">
                    <div className="flex items-center gap-4 text-left">
                      <div className="w-16 h-16 rounded-2xl bg-gray-100 flex-shrink-0 overflow-hidden border border-gray-100 relative">
                        {p.image_url ? (
                          <img src={p.image_url} alt={p.name} className="w-full h-full object-cover" />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-gray-300">
                            <Package size={24} />
                          </div>
                        )}
                        {p.stock_quantity === 0 && (
                          <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                            <span className="text-[8px] font-black text-white uppercase tracking-tighter bg-rose-500 px-1 rounded">Rupture</span>
                          </div>
                        )}
                      </div>

                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <h4 className="font-bold text-gray-900 truncate">{p.name}</h4>
                          <span className="text-[10px] font-black text-wa-teal bg-wa-chat px-2 py-0.5 rounded-full uppercase tracking-tighter">
                            {p.categories?.name || 'Sans catégorie'}
                          </span>
                        </div>
                        <div className="flex items-center gap-4 mt-1">
                          <p className="text-sm font-black text-wa-teal-dark">{p.price.toLocaleString()} F</p>
                          <div className="flex items-center gap-1">
                            <div className={`w-1.5 h-1.5 rounded-full ${p.stock_quantity > 0 ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>
                            <p className="text-[10px] font-bold text-gray-500">{p.stock_quantity} en stock</p>
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => openEditModal(p)}
                          className="p-2 text-wa-teal hover:bg-wa-chat rounded-xl transition-all"
                          title="Modifier"
                        >
                          <Edit3 size={18} />
                        </button>
                        <button 
                          onClick={() => deleteProduct(p.id)}
                          className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                          title="Supprimer"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>

      {showAddModal && (
        <AddProductModal 
          onClose={() => setShowAddModal(false)} 
          categories={categories} 
          storeId={store?.id}
          productToEdit={productToEdit}
          onSuccess={() => {
            fetchProducts();
            setShowAddModal(false);
          }}
        />
      )}
    </div>
  );
}

'use client';
import { useEffect, useRef, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/context/AuthContext';
import { deleteCloudinaryByUrl, uploadImage } from '@/lib/cloudinary';
import { useRouter } from 'next/navigation';
import { 
  Settings, Save, Loader2, ArrowLeft, Image as ImageIcon, 
  Palette, Type, Megaphone, Globe, Info, CheckCircle2, 
  Camera, Trash2, Smartphone
} from 'lucide-react';
import Link from 'next/link';

export default function StoreSettingsPage() {
  const { session } = useAuth();
  const router = useRouter();

  const [storeId, setStoreId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [uploadingField, setUploadingField] = useState('');
  const [storeSchema, setStoreSchema] = useState({ hasCity: false, hasPhone: false });
  const [initialMedia, setInitialMedia] = useState({ logo_url: '', banner_url: '' });
  const tempUploadedUrlsRef = useRef(new Set());
  const saveSucceededRef = useRef(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    city: '',
    phone: '',
    slug: '',
    logo_url: '',
    banner_url: '',
    theme_color: '#128C7E',
    secondary_color: '#F3F4F6',
    font_family: 'Inter',
    custom_message: '',
    whatsapp_number: ''
  });

  useEffect(() => {
    if (!session?.id) return;
    async function fetchStore() {
      const { data } = await supabase.from('stores').select('*').eq('owner_id', session.id).single();
      if (data) {
        setStoreSchema({
          hasCity: Object.prototype.hasOwnProperty.call(data, 'city'),
          hasPhone: Object.prototype.hasOwnProperty.call(data, 'phone'),
        });
        setStoreId(data.id);
        setInitialMedia({
          logo_url: data.logo_url || '',
          banner_url: data.banner_url || '',
        });
        setFormData({
          name: data.name || '',
          description: data.description || '',
          city: data.city || '',
          phone: data.phone || '',
          slug: data.slug || '',
          logo_url: data.logo_url || '',
          banner_url: data.banner_url || '',
          theme_color: data.theme_color || '#128C7E',
          secondary_color: data.secondary_color || '#F3F4F6',
          font_family: data.font_family || 'Inter',
          custom_message: data.custom_message || '',
          whatsapp_number: data.whatsapp_number || ''
        });
      }
    }
    fetchStore();
  }, [session]);

  useEffect(() => {
    return () => {
      if (saveSucceededRef.current) return;
      const pending = Array.from(tempUploadedUrlsRef.current);
      pending.forEach((url) => deleteCloudinaryByUrl(url));
    };
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFileUpload = async (fieldName, file) => {
    if (!file) return;
    try {
      setUploadingField(fieldName);
      const previousUrl = formData[fieldName];
      const { secureUrl } = await uploadImage(file, { folder: 'vestyle/stores' });
      if (!secureUrl) throw new Error("Upload invalide");
      if (previousUrl && previousUrl !== secureUrl && tempUploadedUrlsRef.current.has(previousUrl)) {
        await deleteCloudinaryByUrl(previousUrl);
        tempUploadedUrlsRef.current.delete(previousUrl);
      }
      setFormData((prev) => ({ ...prev, [fieldName]: secureUrl }));
      tempUploadedUrlsRef.current.add(secureUrl);
    } catch (err) {
      alert("Erreur upload image: " + (err?.message || "Impossible de televerser l'image"));
    } finally {
      setUploadingField('');
    }
  };

  const handleRemoveImage = async (fieldName) => {
    const currentUrl = formData[fieldName];
    if (!currentUrl) return;
    if (tempUploadedUrlsRef.current.has(currentUrl)) {
      await deleteCloudinaryByUrl(currentUrl);
      tempUploadedUrlsRef.current.delete(currentUrl);
    }
    setFormData((prev) => ({ ...prev, [fieldName]: '' }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!storeId) return;

    setLoading(true);
    const { error } = await supabase.from('stores').update({
      name: formData.name,
      description: formData.description,
      ...(storeSchema.hasCity ? { city: formData.city } : {}),
      ...(storeSchema.hasPhone ? { phone: formData.phone } : {}),
      slug: formData.slug,
      logo_url: formData.logo_url,
      banner_url: formData.banner_url,
      theme_color: formData.theme_color,
      secondary_color: formData.secondary_color,
      font_family: formData.font_family,
      custom_message: formData.custom_message,
      whatsapp_number: formData.whatsapp_number
    }).eq('id', storeId);

    setLoading(false);
    if (error) {
      alert("Erreur lors de la mise à jour : " + error.message);
    } else {
      const cleanupTasks = [];
      ['logo_url', 'banner_url'].forEach((fieldName) => {
        const oldUrl = initialMedia[fieldName];
        const newUrl = formData[fieldName];
        if (oldUrl && oldUrl !== newUrl) cleanupTasks.push(deleteCloudinaryByUrl(oldUrl));
      });
      if (cleanupTasks.length > 0) await Promise.allSettled(cleanupTasks);
      saveSucceededRef.current = true;
      tempUploadedUrlsRef.current.clear();
      router.push('/dashboard');
    }
  };

  if (session === undefined) return <div className="min-h-screen bg-wa-bg flex justify-center items-center"><Loader2 className="animate-spin text-wa-teal" size={48} /></div>;

  return (
    <div className="max-w-5xl mx-auto space-y-8 pb-20">
      {/* Header Premium */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm text-left">
        <div className="space-y-1">
          <h1 className="text-3xl font-black text-gray-900 tracking-tight flex items-center gap-3">
            <Settings className="text-wa-teal" size={32} />
            Configuration Boutique
          </h1>
          <p className="text-gray-500 font-medium">Sublimez l'apparence et les réglages de votre espace client.</p>
        </div>
        <Link href="/dashboard" className="flex items-center gap-2 px-5 py-3 bg-gray-50 text-gray-500 font-black rounded-2xl hover:bg-gray-100 transition-all text-xs uppercase tracking-widest">
          <ArrowLeft size={16} /> Retour
        </Link>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Colonne de Gauche : Infos de Base & Branding */}
        <div className="lg:col-span-2 space-y-8">

          {/* Identité Section */}
          <section className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm space-y-6 text-left">
            <div className="flex items-center gap-3 mb-2">
              <div className="p-2 bg-wa-chat rounded-xl text-wa-teal"><Globe size={20} /></div>
              <h2 className="text-xl font-black text-gray-900">Identité & Accès</h2>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Nom de la boutique</label>
                <input required type="text" name="name" value={formData.name} onChange={handleChange} className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-2xl px-5 py-3.5 text-sm font-bold outline-none transition-all" />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Lien (Slug)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold text-sm">/boutique/</span>
                  <input type="text" name="slug" value={formData.slug} onChange={handleChange} className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-2xl pl-24 pr-5 py-3.5 text-sm font-bold outline-none transition-all" />
                </div>
              </div>

              <div className="md:col-span-2 space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Description Boutique</label>
                <textarea name="description" value={formData.description} onChange={handleChange} rows="3" className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-2xl px-5 py-3.5 text-sm font-bold outline-none transition-all resize-none"></textarea>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Numéro WhatsApp Client</label>
                <div className="relative">
                  <Smartphone className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500" size={18} />
                  <input type="text" name="whatsapp_number" value={formData.whatsapp_number} onChange={handleChange} placeholder="237655..." className="w-full bg-gray-50 border-2 border-transparent focus:border-wa-teal focus:bg-white rounded-2xl pl-12 pr-5 py-3.5 text-sm font-bold outline-none transition-all" />
                </div>
              </div>
            </div>
          </section>

          {/* Design & Style Section */}
          <section className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm space-y-6 text-left">
            <div className="flex items-center gap-3 mb-2">
              <div className="p-2 bg-amber-50 rounded-xl text-amber-500"><Palette size={20} /></div>
              <h2 className="text-xl font-black text-gray-900">Style & Branding</h2>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Thème Visuel</label>
                <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-3xl border border-gray-100">
                  <div className="relative group">
                    <input type="color" name="theme_color" value={formData.theme_color} onChange={handleChange} className="w-16 h-16 rounded-2xl cursor-pointer border-4 border-white shadow-lg overflow-hidden" />
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity">
                      <CheckCircle2 className="text-white drop-shadow-md" size={24} />
                    </div>
                  </div>
                  <div className="flex-1">
                    <p className="text-sm font-black text-gray-900 uppercase tracking-tighter">{formData.theme_color}</p>
                    <p className="text-[10px] font-bold text-gray-400 uppercase">Couleur Principale</p>
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">Typographie</label>
                <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-3xl border border-gray-100">
                  <div className="p-3 bg-white rounded-2xl text-gray-400 shadow-sm"><Type size={24} /></div>
                  <select name="font_family" value={formData.font_family} onChange={handleChange} className="flex-1 bg-transparent border-none outline-none font-black text-sm">
                    <option value="Inter">Inter (Moderne)</option>
                    <option value="'Outfit', sans-serif">Outfit (Élégant)</option>
                    <option value="'Playfair Display', serif">Playfair (Luxe)</option>
                    <option value="'Montserrat', sans-serif">Montserrat (Bold)</option>
                  </select>
                </div>
              </div>
            </div>
          </section>

          {/* Section PROMOTION (EMBELLIE) */}
          <section className="bg-gradient-to-br from-wa-teal to-wa-teal-dark p-8 rounded-[40px] text-white shadow-xl shadow-wa-teal/20 space-y-6 text-left relative overflow-hidden group">
             <div className="relative z-10">
               <div className="flex items-center gap-3 mb-2">
                 <div className="p-2 bg-white/20 backdrop-blur-md rounded-xl text-white"><Megaphone size={20} /></div>
                 <h2 className="text-xl font-black">Section Promotionnelle</h2>
               </div>
               <p className="text-white/80 text-sm font-medium mb-6">Ce message s'affichera en haut de votre boutique pour attirer l'œil de vos clients.</p>

               <div className="space-y-4">
                 <div className="relative">
                   <textarea 
                    name="custom_message" 
                    value={formData.custom_message} 
                    onChange={handleChange} 
                    rows="2" 
                    placeholder="Ex: 🎉 PROMO : -20% sur toute la collection avec le code VESTYLE !"
                    className="w-full bg-white/10 backdrop-blur-md border-2 border-white/20 focus:border-white focus:bg-white/20 rounded-2xl px-5 py-4 text-sm font-black placeholder:text-white/40 outline-none transition-all resize-none"
                   ></textarea>
                 </div>
                 <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-60">
                    <Info size={12} />
                    <span>Apparaît comme une bannière animée sur la boutique</span>
                 </div>
               </div>
             </div>
             <Megaphone className="absolute -right-8 -bottom-8 opacity-10 group-hover:scale-110 transition-transform duration-700" size={160} />
          </section>
        </div>

        {/* Colonne de Droite : Médias & Sauvegarde */}
        <div className="space-y-8">

          {/* Logo & Banner Section */}
          <section className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm space-y-8 text-left">
             <div className="flex items-center gap-3 mb-2">
              <div className="p-2 bg-rose-50 rounded-xl text-rose-500"><ImageIcon size={20} /></div>
              <h2 className="text-xl font-black text-gray-900">Visuels</h2>
            </div>

            {/* Logo Upload */}
            <div className="space-y-4">
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Logo Boutique</p>
              <div className="relative group aspect-square max-w-[120px] mx-auto">
                <div className="w-full h-full rounded-[32px] bg-gray-50 border-2 border-dashed border-gray-200 flex items-center justify-center overflow-hidden">
                  {formData.logo_url ? (
                    <img src={formData.logo_url} className="w-full h-full object-cover" alt="Logo" />
                  ) : (
                    <Camera className="text-gray-300" size={32} />
                  )}
                  {uploadingField === 'logo_url' && (
                    <div className="absolute inset-0 bg-white/80 backdrop-blur-sm flex items-center justify-center">
                      <Loader2 className="animate-spin text-wa-teal" size={24} />
                    </div>
                  )}
                </div>
                <label className="absolute -bottom-2 -right-2 p-2.5 bg-wa-teal text-white rounded-xl shadow-lg cursor-pointer hover:bg-wa-teal-dark transition-all active:scale-95">
                  <Camera size={18} />
                  <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileUpload('logo_url', e.target.files?.[0])} />
                </label>
                {formData.logo_url && (
                  <button type="button" onClick={() => handleRemoveImage('logo_url')} className="absolute -top-2 -right-2 p-2.5 bg-rose-500 text-white rounded-xl shadow-lg hover:bg-rose-600 transition-all">
                    <Trash2 size={18} />
                  </button>
                )}
              </div>
            </div>

            {/* Banner Upload */}
            <div className="space-y-4">
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Bannière de Fond</p>
              <div className="relative group w-full aspect-[2/1] rounded-3xl bg-gray-50 border-2 border-dashed border-gray-200 flex items-center justify-center overflow-hidden">
                {formData.banner_url ? (
                  <img src={formData.banner_url} className="w-full h-full object-cover" alt="Bannière" />
                ) : (
                  <ImageIcon className="text-gray-300" size={32} />
                )}
                <label className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/20 backdrop-blur-sm cursor-pointer">
                  <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl text-xs font-black text-gray-900 uppercase tracking-widest shadow-xl">
                    <Camera size={16} /> Changer
                  </div>
                  <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileUpload('banner_url', e.target.files?.[0])} />
                </label>
              </div>
            </div>
          </section>

          {/* Action Card */}
          <div className="bg-gray-900 p-8 rounded-[40px] shadow-2xl space-y-6">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-white/10 rounded-2xl flex items-center justify-center text-wa-teal">
                <CheckCircle2 size={24} />
              </div>
              <p className="text-white font-black tracking-tight text-lg">Prêt à publier ?</p>
            </div>
            <p className="text-gray-400 text-sm font-medium leading-relaxed">Assurez-vous que vos images sont de haute qualité pour attirer plus de clients.</p>
            <button 
              type="submit" 
              disabled={loading || !!uploadingField}
              className="w-full py-4 bg-wa-teal hover:bg-wa-teal-dark disabled:bg-gray-700 text-white font-black rounded-2xl shadow-xl shadow-wa-teal/20 transition-all active:scale-95 flex items-center justify-center gap-3"
            >
              {loading ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
              Enregistrer les changements
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}

