'use client';
import { useEffect, useState, useMemo, useCallback } from 'react';
import { ShoppingBag, Search, Store, Sparkles, ChevronRight, X, SlidersHorizontal, Zap } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import Link from 'next/link';

// Helper to safely call RPC without crashing if not a promise
async function safeRpc(fn) {
  try { await fn; } catch (_) {}
}

export default function ClientDiscovery({ initialSearchQuery = '' }) {
  const [products, setProducts] = useState([]);
  const [stores, setStores] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Filters & Sorting
  const [searchQuery, setSearchQuery] = useState(initialSearchQuery);
  const [activeCategory, setActiveCategory] = useState('all');
  const [sortBy, setSortBy] = useState('boost'); // 'boost', 'newest', 'price_asc', 'price_desc'
  const [showFilters, setShowFilters] = useState(false);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      // Produits réels avec boutique + catégorie, triés par boost puis vues puis date
      const { data: prodData, error: prodErr } = await supabase
        .from('products')
        .select(`
          id, name, price, image_url, created_at, category_id, is_active,
          is_boosted, is_promo, daily_views,
          stores ( id, name, slug, logo_url ),
          categories ( name )
        `)
        .eq('is_active', true)
        .order('is_boosted', { ascending: false })
        .order('is_promo', { ascending: false })
        .order('daily_views', { ascending: false })
        .order('created_at', { ascending: false });

      if (prodErr) throw prodErr;

      // Récupérer uniquement les boutiques qui ont au moins un produit actif
      // On passe par les produits pour extraire les store_id uniques avec produits
      const { data: storeIdsData } = await supabase
        .from('products')
        .select('store_id')
        .eq('is_active', true);

      const activeStoreIds = [...new Set((storeIdsData || []).map(p => p.store_id))];

      let storeData = [];
      if (activeStoreIds.length > 0) {
        const { data: sd, error: storeErr } = await supabase
          .from('stores')
          .select('id, name, slug, logo_url, city, is_boosted, daily_views')
          .in('id', activeStoreIds)
          .order('is_boosted', { ascending: false })
          .order('daily_views', { ascending: false });

        if (storeErr) throw storeErr;
        storeData = sd || [];
      }

      // Catégories réelles
      const { data: catData } = await supabase.from('categories').select('*');

      const normalized = (prodData || []).map(p => ({
        ...p,
        category: p.categories?.name || 'Autre',
      }));

      setProducts(normalized);
      setStores(storeData || []);

      if (catData && catData.length > 0) {
        setCategories(catData);
      } else {
        // Dériver les catégories depuis les produits si la table est vide
        const uniqueCats = [...new Set(normalized.map(p => p.category).filter(Boolean))];
        setCategories(uniqueCats.map(name => ({ id: name, name })));
      }
    } catch (err) {
      console.error('Erreur chargement données:', err);
      setError('Impossible de charger les données. Vérifiez votre connexion.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  // Incrémenter vues produit (fire-and-forget)
  const trackProductView = useCallback((productId) => {
    safeRpc(supabase.rpc('increment_product_view', { prod_id: productId }));
  }, []);

  // Incrémenter vues boutique (fire-and-forget)
  const trackStoreView = useCallback((storeId) => {
    safeRpc(supabase.rpc('increment_store_view', { st_id: storeId }));
  }, []);

  // State for Meilisearch results
  const [meiliResults, setMeiliResults] = useState({ products: [], stores: [] });
  const [isSearching, setIsSearching] = useState(false);

  // Search effect
  useEffect(() => {
    const performSearch = async () => {
      if (!searchQuery.trim()) {
        setMeiliResults({ products: [], stores: [] });
        return;
      }

      setIsSearching(true);
      try {
        const { publicProductsIndex, publicStoresIndex } = await import('@/lib/meilisearch');

        // Parallel search for products and stores
        const [prodSearch, storeSearch] = await Promise.all([
          publicProductsIndex.search(searchQuery, {
            limit: 12,
            attributesToHighlight: ['name'],
          }),
          publicStoresIndex.search(searchQuery, {
            limit: 4,
          })
        ]);

        setMeiliResults({
          products: prodSearch.hits.map(hit => {
            const local = products.find(p => p.id === hit.id);
            return local || { ...hit, stores: { name: hit.store_name, slug: hit.store_slug } };
          }),
          stores: storeSearch.hits
        });
      } catch (err) {
        console.error('Meilisearch search error:', err);
      } finally {
        setIsSearching(false);
      }
    };

    const timeoutId = setTimeout(performSearch, 300);
    return () => clearTimeout(timeoutId);
  }, [searchQuery, products]);

  // Produits filtrés + triés côté client
  const filteredProducts = useMemo(() => {
    let result = searchQuery.trim() && meiliResults.products.length > 0 ? [...meiliResults.products] : [...products];

    // Client-side fallback if meili is empty but query exists
    if (searchQuery.trim() && meiliResults.products.length === 0) {
      const q = searchQuery.toLowerCase();
      result = products.filter(p =>
        p.name.toLowerCase().includes(q) ||
        (p.stores?.name || '').toLowerCase().includes(q)
      );
    }

    if (activeCategory !== 'all') {
      result = result.filter(p => p.category === activeCategory);
    }

    // Apply sorting
    switch (sortBy) {
      case 'price_asc': result.sort((a, b) => a.price - b.price); break;
      case 'price_desc': result.sort((a, b) => b.price - a.price); break;
      case 'newest': result.sort((a, b) => new Date(b.created_at) - new Date(a.created_at)); break;
      default:
        result.sort((a, b) => {
          if (a.is_boosted !== b.is_boosted) return b.is_boosted ? 1 : -1;
          if (a.is_promo !== b.is_promo) return b.is_promo ? 1 : -1;
          return b.daily_views - a.daily_views;
        });
    }
    return result;
  }, [products, searchQuery, activeCategory, sortBy, meiliResults.products]);

  // Handle scroll reveal
  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('opacity-100', 'translate-y-0');
          entry.target.classList.remove('opacity-0', 'translate-y-10');
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.reveal').forEach(el => observer.observe(el));
    return () => observer.disconnect();
  }, [filteredProducts, meiliResults, stores]);

  if (loading) {
    return (
      <div className="flex justify-center items-center py-40">
        <div className="w-14 h-14 border-4 border-wa-teal border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <div className="space-y-12 pb-20">

      {/* ═══════════════════════════════════════════
          1. WHATSAPP STYLE SEARCH BAR
      ════════════════════════════════════════════ */}
      <section className="sticky top-[70px] z-30 transition-all duration-500">
        <div className="bg-white/95 backdrop-blur-md px-4 py-3 rounded-2xl shadow-[0_8px_40px_rgb(0,0,0,0.06)] border border-neutral-100 flex items-center gap-3">
          <div className="flex-1 relative flex items-center">
            <Search className={`absolute left-3 transition-colors ${isSearching ? 'text-wa-teal' : 'text-neutral-400'}`} size={18} />
            <input
              type="text"
              placeholder="Chercher produits, boutiques..."
              className="w-full pl-10 pr-10 py-2.5 bg-neutral-100/50 rounded-xl text-sm font-medium border-none outline-none focus:ring-0"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
            {isSearching && (
              <div className="absolute right-3">
                <div className="w-4 h-4 border-2 border-wa-teal border-t-transparent rounded-full animate-spin"></div>
              </div>
            )}
          </div>
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`p-2.5 rounded-xl transition-all ${showFilters ? 'bg-wa-teal text-white shadow-lg shadow-wa-teal/20' : 'bg-neutral-100 text-neutral-600'}`}
          >
            <SlidersHorizontal size={20} />
          </button>
        </div>

        {showFilters && (
          <div className="mt-2 bg-white p-4 rounded-2xl shadow-2xl border border-neutral-100 animate-fade-in space-y-4">
            <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
              {['all', ...categories.map(c => c.name || c)].map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`flex-shrink-0 px-5 py-2 rounded-full text-xs font-black transition-all ${activeCategory === cat ? 'bg-wa-teal text-white shadow-md' : 'bg-neutral-100 text-neutral-500 hover:bg-neutral-200'}`}
                >
                  {cat === 'all' ? 'TOUT' : cat.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
        )}
      </section>

      {/* ═══════════════════════════════════════════
          2. GLOBAL SEARCH RESULTS (STORES + PRODUCTS)
      ════════════════════════════════════════════ */}
      {searchQuery && (
        <div className="space-y-10">
          {/* Section Boutiques dans la recherche */}
          {meiliResults.stores.length > 0 && (
            <section className="reveal opacity-0 translate-y-10 transition-all duration-700">
              <h2 className="text-xs font-black text-neutral-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                <Store size={14} /> Boutiques trouvées
              </h2>
              <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
                {meiliResults.stores.map(store => (
                  <Link key={store.id} href={`/boutique/${store.slug}`} className="flex-shrink-0 group w-20 flex flex-col items-center">
                    <div className="w-16 h-16 rounded-full overflow-hidden border-2 border-neutral-100 group-hover:border-wa-teal transition-all p-[2px] bg-white">
                      <img src={store.logo_url || '/placeholder-store.png'} className="w-full h-full object-cover rounded-full" alt={store.name} />
                    </div>
                    <span className="text-[10px] font-bold text-neutral-800 mt-2 truncate w-full text-center">{store.name}</span>
                  </Link>
                ))}
              </div>
            </section>
          )}

          {/* Section Produits dans la recherche */}
          <section className="reveal opacity-0 translate-y-10 transition-all duration-700">
            <h2 className="text-xs font-black text-neutral-400 uppercase tracking-widest mb-6 flex items-center gap-2">
              <ShoppingBag size={14} /> Produits trouvés ({filteredProducts.length})
            </h2>
            <div className="grid grid-cols-1 gap-6">
              {filteredProducts.map((item, idx) => (
                <ProductCard key={item.id} item={item} idx={idx} trackProductView={trackProductView} />
              ))}
            </div>
          </section>
        </div>
      )}

      {/* ═══════════════════════════════════════════
          3. REGULAR FEED (WHATSAPP STATUS + ALL PRODUCTS)
      ════════════════════════════════════════════ */}
      {!searchQuery && (
        <>
          {/* Status Style Stores */}
          {stores.length > 0 && (
            <section className="reveal opacity-0 translate-y-10 transition-all duration-700">
              <div className="flex items-center justify-between mb-4 px-2">
                <h2 className="text-[11px] font-black text-neutral-400 uppercase tracking-widest">En ligne maintenant</h2>
                <Link href="/boutiques" className="text-xs font-bold text-wa-teal">Voir tout</Link>
              </div>
              <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar">
                {stores.map(store => (
                  <Link key={store.id} href={`/boutique/${store.slug}`} className="flex-shrink-0 group flex flex-col items-center w-20">
                    <div className={`relative p-[3px] rounded-full border-2 ${store.is_boosted ? 'border-wa-teal' : 'border-neutral-200'} group-hover:border-wa-teal transition-all duration-500`}>
                      <div className="w-16 h-16 rounded-full overflow-hidden bg-neutral-100 border border-white shadow-sm">
                        <img src={store.logo_url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt={store.name} />
                      </div>
                    </div>
                    <span className="text-[11px] font-bold text-neutral-800 mt-2 truncate w-full text-center group-hover:text-wa-teal">{store.name}</span>
                  </Link>
                ))}
              </div>
            </section>
          )}

          {/* All Products Feed */}
          <section className="reveal opacity-0 translate-y-10 transition-all duration-700">
            <h2 className="text-[11px] font-black text-neutral-400 uppercase tracking-widest mb-6 px-2">Découvrir le marché</h2>
            <div className="grid grid-cols-1 gap-6">
              {filteredProducts.map((item, idx) => (
                <ProductCard key={item.id} item={item} idx={idx} trackProductView={trackProductView} />
              ))}
            </div>
          </section>
        </>
      )}
    </div>
  );
}

// Sub-component for Product Cards with Animations
function ProductCard({ item, idx, trackProductView }) {
  return (
    <Link
      href={`/boutique/${item.stores?.slug || item.store_slug}`}
      onClick={() => trackProductView(item.id)}
      className="reveal opacity-0 translate-y-10 group flex gap-4 p-4 bg-white rounded-[2rem] border border-neutral-100 hover:shadow-2xl hover:shadow-neutral-200/50 transition-all duration-500"
      style={{ transitionDelay: `${idx * 50}ms` }}
    >
      <div className="relative w-32 h-32 sm:w-44 sm:h-44 rounded-2xl overflow-hidden bg-neutral-50 flex-shrink-0">
        <img src={item.image_url} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
        {item.is_promo && (
          <div className="absolute top-2 left-2 bg-orange-500 text-white text-[9px] font-black px-2 py-1 rounded-lg">PROMO</div>
        )}
      </div>
      <div className="flex-1 py-1 flex flex-col justify-between">
        <div>
          <div className="text-[10px] font-bold text-wa-teal uppercase tracking-widest mb-1">{item.stores?.name || item.store_name}</div>
          <h3 className="text-base sm:text-xl font-black text-neutral-900 group-hover:text-wa-teal transition-colors line-clamp-1">{item.name}</h3>
          <p className="text-xs text-neutral-400 font-medium line-clamp-2 mt-1">{item.description || 'Produit de qualité supérieure disponible maintenant.'}</p>
        </div>
        <div className="flex items-center justify-between">
          <span className="text-xl font-black text-neutral-900">{Number(item.price).toLocaleString('fr-FR')} F</span>
          <div className="flex items-center gap-2">
            <div className="hidden sm:flex items-center gap-1 px-3 py-1.5 rounded-full bg-neutral-50 text-neutral-500 text-[10px] font-bold">
              <Zap size={12} className="text-orange-500" /> Populaire
            </div>
            <div className="w-10 h-10 bg-wa-teal text-white rounded-full flex items-center justify-center shadow-lg shadow-wa-teal/20 group-hover:scale-110 transition-transform">
              <ChevronRight size={20} />
            </div>
          </div>
        </div>
      </div>
    </Link>
  );
}

'use client';
import { useEffect, useState } from 'react';
import { ShoppingBag, ArrowRight, Tag, Sprout } from 'lucide-react';
import { supabase } from '@/lib/supabase';

export default function ProductsPreview() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchProducts() {
      // Vrais produits de la base de données, contrôlés par un algorithme. Pas de simulation.
      const { data, error } = await supabase
        .from('products')
        .select(`
          id, 
          name, 
          price, 
          image_url, 
          created_at,
          stores ( name )
        `)
        .eq('is_active', true)
        .order('created_at', { ascending: false })
        .limit(8);

      if (!error && data) {
        setProducts(data);
      }
      setLoading(false);
    }
    fetchProducts();
  }, []);

  return (
    <section className="py-24 bg-wa-bg relative overflow-hidden">

      {/* Touches WhatsApp (Fonds flous) */}
      <div className="absolute top-1/2 left-0 w-[500px] h-[500px] bg-wa-chat rounded-full blur-[150px] opacity-40 pointer-events-none"></div>
      <div className="absolute bottom-0 right-0 w-[600px] h-[500px] bg-wa-green/10 rounded-full blur-[150px] pointer-events-none"></div>

      <div className="max-w-7xl mx-auto px-6 relative z-10">

        {/* Header de la section */}
        <div className="flex flex-col md:flex-row justify-between items-end gap-6 mb-12">
          <div className="max-w-2xl">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-wa-chat text-xs font-bold text-wa-teal uppercase tracking-widest mb-6">
               <Sprout size={14} className="text-wa-teal" />
               Nouveautés
            </div>
             <h2 className="text-3xl md:text-4xl font-bold text-wa-teal-dark mb-4 tracking-tight">
               Boutiques Récentes
             </h2>
             <p className="text-base text-neutral-600">
               Découvrez les derniers produits ajoutés par les vendeurs sur la plateforme.
             </p>
          </div>
          <button className="group flex items-center gap-2 text-sm font-bold text-wa-teal uppercase tracking-widest pb-1 border-b border-wa-teal hover:text-wa-teal-dark hover:border-wa-teal-dark transition-colors">
            Voir tout
            <ArrowRight size={16} className="transition-transform duration-300 group-hover:translate-x-1" />
          </button>
        </div>

        {/* Grille des produits ou Chargement */}
        {loading ? (
          <div className="flex justify-center items-center py-24">
             <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-wa-teal"></div>
          </div>
        ) : products.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl shadow-sm">
             <ShoppingBag className="mx-auto text-neutral-300 mb-6" size={48} strokeWidth={1} />
             <h3 className="text-xl font-bold text-wa-teal-dark mb-2">Les rayons sont vides pour le moment</h3>
             <p className="text-neutral-500 text-base">De nouveaux produits arrivent bientôt.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-x-6 gap-y-12">
            {products.map((item, idx) => (
              <div
                key={item.id}
                className="group cursor-pointer flex flex-col h-full opacity-100 animate-fade-in"
              >
                {/* Image Conteneur */}
                <div className="relative w-full aspect-[4/5] rounded-3xl overflow-hidden mb-4 bg-white shadow-sm border border-neutral-100 group-hover:border-wa-teal transition-colors duration-300">
                  <img 
                    src={item.image_url || "https://images.unsplash.com/photo-1550989460-0adf9ea622e2?q=80&w=800&auto=format&fit=crop"} 
                    alt={item.name} 
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                  />
                  {/* Badge Vendeur */}
                  {item.stores && item.stores.name && (
                    <div className="absolute bottom-4 left-4 right-4 bg-white/95 backdrop-blur-sm px-4 py-2.5 rounded-2xl flex flex-col shadow-md border border-neutral-100 transform translate-y-2 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300">
                       <span className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest leading-none mb-1">Boutique</span>
                       <span className="text-sm text-wa-teal-dark font-bold truncate leading-none">{item.stores.name}</span>
                    </div>
                  )}
                </div>

                {/* Contenu Produit */}
                <div className="flex flex-col flex-1 justify-between px-1">
                  <div>
                    <h3 className="text-lg font-bold text-wa-teal-dark mb-1 group-hover:text-wa-teal transition-colors line-clamp-1">
                      {item.name}
                    </h3>
                  </div>

                  <div className="flex items-center justify-between mt-auto pt-2">
                    <span className="text-base font-bold text-wa-teal">
                      {Number(item.price).toLocaleString('fr-FR', { style: 'currency', currency: 'XAF' })}
                    </span>
                    <button className="w-10 h-10 rounded-full bg-wa-chat text-wa-teal flex items-center justify-center hover:bg-wa-teal hover:text-white transition-colors group-hover:scale-105 duration-300">
                      <ShoppingBag size={18} strokeWidth={2} />
                    </button>
                  </div>
                </div>

              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
